1	<!DOCTYPE html>
2	<html lang="ja">
3	<head>
4	  <meta charset="UTF-8">
5	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	  <title>ばね自動選定システム</title>
7	  <style>
8	    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
9	
10	    body {
11	      font-family: 'Segoe UI', 'Meiryo', sans-serif;
12	      font-size: 13px;
13	      background: #f0f2f5;
14	      color: #1a1a1a;
15	      display: flex;
16	      height: 100vh;
17	      overflow: hidden;
18	    }
19	
20	    /* ─── サイドバー ─── */
21	    #sidebar {
22	      width: 320px;
23	      min-width: 320px;
24	      background: #fff;
25	      border-right: 1px solid #dde1e7;
26	      display: flex;
27	      flex-direction: column;
28	      overflow: hidden;
29	    }
30	
31	    #sidebar-header {
32	      padding: 14px 16px 10px;
33	      border-bottom: 1px solid #dde1e7;
34	      background: #1e3a5f;
35	      color: #fff;
36	    }
37	    #sidebar-header h1 {
38	      font-size: 1rem;
39	      font-weight: 700;
40	      letter-spacing: 0.03em;
41	    }
42	    #sidebar-header .sub {
43	      font-size: 0.72rem;
44	      color: #a8c4e0;
45	      margin-top: 2px;
46	    }
47	
48	    /* タブ */
49	    .tab-bar {
50	      display: flex;
51	      border-bottom: 2px solid #dde1e7;
52	      background: #f8f9fb;
53	    }
54	    .tab-btn {
55	      flex: 1;
56	      padding: 8px 4px;
57	      font-size: 0.75rem;
58	      font-weight: 600;
59	      color: #666;
60	      background: none;
61	      border: none;
62	      cursor: pointer;
63	      border-bottom: 2px solid transparent;
64	      margin-bottom: -2px;
65	      transition: color 0.15s, border-color 0.15s;
66	    }
67	    .tab-btn.active {
68	      color: #1e3a5f;
69	      border-bottom-color: #1e3a5f;
70	      background: #fff;
71	    }
72	    .tab-btn:hover:not(.active) { color: #1e3a5f; background: #eef2f8; }
73	
74	    /* スクロールエリア */
75	    .tab-content {
76	      display: none;
77	      flex: 1;
78	      overflow-y: auto;
79	      padding: 12px 14px 20px;
80	    }
81	    .tab-content.active { display: block; }
82	
83	    /* セクション */
84	    .section {
85	      margin-bottom: 14px;
86	    }
87	    .section-title {
88	      font-size: 0.72rem;
89	      font-weight: 700;
90	      color: #fff;
91	      background: #3a5a8a;
92	      padding: 3px 8px;
93	      border-radius: 3px;
94	      margin-bottom: 8px;
95	      letter-spacing: 0.04em;
96	    }
97	
98	    /* フォーム部品 */
99	    .form-row {
100	      display: flex;
101	      align-items: center;
102	      margin-bottom: 7px;
103	      gap: 6px;
104	    }
105	    .form-row label {
106	      font-size: 0.75rem;
107	      color: #444;
108	      flex: 0 0 105px;
109	      line-height: 1.4;
110	    }
111	    .form-row input[type="number"],
112	    .form-row select {
113	      flex: 1;
114	      padding: 4px 7px;
115	      border: 1px solid #c8cdd6;
116	      border-radius: 4px;
117	      font-size: 0.8rem;
118	      background: #fff;
119	      color: #1a1a1a;
120	    }
121	    .form-row input[type="number"]:focus,
122	    .form-row select:focus {
123	      outline: none;
124	      border-color: #3a7bd5;
125	      box-shadow: 0 0 0 2px rgba(58,123,213,0.12);
126	    }
127	    .unit {
128	      font-size: 0.72rem;
129	      color: #888;
130	      flex: 0 0 28px;
131	    }
132	
133	    .hint {
134	      font-size: 0.68rem;
135	      color: #777;
136	      background: #f4f6fa;
137	      border-left: 2px solid #aab;
138	      padding: 3px 8px;
139	      margin: -3px 0 8px;
140	      line-height: 1.5;
141	    }
142	
143	    /* 摩擦係数バッジ */
144	    .mu-badge {
145	      display: inline-flex;
146	      align-items: center;
147	      gap: 4px;
148	      background: #e8f0fb;
149	      border: 1px solid #c0d4f0;
150	      border-radius: 3px;
151	      padding: 2px 8px;
152	      font-size: 0.75rem;
153	      color: #1e3a5f;
154	      font-weight: 600;
155	    }
156	
157	    /* 材料警告 */
158	    .material-warn {
159	      display: none;
160	      background: #fff3cd;
161	      border: 1px solid #ffc107;
162	      border-radius: 4px;
163	      padding: 6px 10px;
164	      font-size: 0.72rem;
165	      color: #856404;
166	      margin: 4px 0 8px;
167	    }
168	    .material-warn.show { display: block; }
169	    .material-warn.ng {
170	      background: #f8d7da;
171	      border-color: #f5c2c7;
172	      color: #842029;
173	    }
174	
175	    /* 計算ボタン */
176	    #calc-btn {
177	      width: 100%;
178	      padding: 10px;
179	      background: #1e3a5f;
180	      color: #fff;
181	      border: none;
182	      border-radius: 5px;
183	      font-size: 0.9rem;
184	      font-weight: 700;
185	      cursor: pointer;
186	      margin-top: 8px;
187	      letter-spacing: 0.05em;
188	      transition: background 0.15s;
189	    }
190	    #calc-btn:hover { background: #2a5090; }
191	
192	    /* ─── メインエリア ─── */
193	    #main {
194	      flex: 1;
195	      display: flex;
196	      flex-direction: column;
197	      overflow: hidden;
198	    }
199	
200	    #main-header {
201	      padding: 10px 20px;
202	      background: #fff;
203	      border-bottom: 1px solid #dde1e7;
204	      display: flex;
205	      align-items: center;
206	      gap: 12px;
207	    }
208	    #main-header .breadcrumb {
209	      font-size: 0.75rem;
210	      color: #888;
211	    }
212	    #main-header .status-badge {
213	      padding: 2px 10px;
214	      border-radius: 12px;
215	      font-size: 0.72rem;
216	      font-weight: 700;
217	      background: #e0e7ef;
218	      color: #555;
219	    }
220	    #main-header .status-badge.ok { background: #d1fae5; color: #065f46; }
221	    #main-header .status-badge.ng { background: #fee2e2; color: #7f1d1d; }
222	    #main-header .status-badge.warn { background: #fef3c7; color: #78350f; }
223	
224	    #main-body {
225	      flex: 1;
226	      display: grid;
227	      grid-template-columns: 1fr 340px;
228	      grid-template-rows: 1fr 1fr;
229	      gap: 12px;
230	      padding: 12px;
231	      overflow: hidden;
232	    }
233	
234	    /* パネル共通 */
235	    .panel {
236	      background: #fff;
237	      border-radius: 6px;
238	      border: 1px solid #dde1e7;
239	      display: flex;
240	      flex-direction: column;
241	      overflow: hidden;
242	    }
243	    .panel-title {
244	      font-size: 0.78rem;
245	      font-weight: 700;
246	      color: #1e3a5f;
247	      padding: 8px 12px;
248	      border-bottom: 1px solid #eef0f4;
249	      background: #f7f9fc;
250	      letter-spacing: 0.04em;
251	    }
252	    .panel-body {
253	      flex: 1;
254	      overflow: auto;
255	      padding: 10px 12px;
256	    }
257	
258	    /* 設置イメージ */
259	    #canvas-panel { grid-row: 1 / 3; }
260	    #canvas-wrap {
261	      flex: 1;
262	      display: flex;
263	      align-items: center;
264	      justify-content: center;
265	      padding: 10px;
266	    }
267	    #install-canvas {
268	      max-width: 100%;
269	      max-height: 100%;
270	    }
271	
272	    /* 診断結果 */
273	    .diag-grid {
274	      display: grid;
275	      grid-template-columns: 1fr 1fr;
276	      gap: 6px;
277	    }
278	    .diag-item {
279	      border: 1px solid #dde1e7;
280	      border-radius: 4px;
281	      padding: 7px 9px;
282	    }
283	    .diag-item .diag-label {
284	      font-size: 0.7rem;
285	      color: #666;
286	      margin-bottom: 3px;
287	    }
288	    .diag-item .diag-val {
289	      font-size: 0.82rem;
290	      font-weight: 700;
291	    }
292	    .diag-item.ok-item { border-color: #86efac; background: #f0fdf4; }
293	    .diag-item.ok-item .diag-val { color: #166534; }
294	    .diag-item.ng-item { border-color: #fca5a5; background: #fef2f2; }
295	    .diag-item.ng-item .diag-val { color: #991b1b; }
296	    .diag-item.warn-item { border-color: #fcd34d; background: #fffbeb; }
297	    .diag-item.warn-item .diag-val { color: #92400e; }
298	    .diag-item.pending-item { border-color: #e2e8f0; background: #f8fafc; }
299	    .diag-item.pending-item .diag-val { color: #94a3b8; }
300	
301	    /* 選定結果テーブル */
302	    .result-table {
303	      width: 100%;
304	      border-collapse: collapse;
305	      font-size: 0.78rem;
306	    }
307	    .result-table th {
308	      background: #f0f4fa;
309	      color: #1e3a5f;
310	      font-weight: 700;
311	      padding: 5px 8px;
312	      text-align: left;
313	      border-bottom: 2px solid #c9d4e6;
314	    }
315	    .result-table td {
316	      padding: 5px 8px;
317	      border-bottom: 1px solid #eef0f4;
318	      vertical-align: middle;
319	    }
320	    .result-table tr:hover td { background: #f7f9fc; }
321	    .result-table .highlight { color: #1e3a5f; font-weight: 700; }
322	
323	    /* 改善提案 */
324	    .proposal-list {
325	      list-style: none;
326	      padding: 0;
327	    }
328	    .proposal-list li {
329	      display: flex;
330	      gap: 8px;
331	      padding: 6px 0;
332	      border-bottom: 1px solid #f0f2f5;
333	      font-size: 0.77rem;
334	      line-height: 1.5;
335	    }
336	    .proposal-list li:last-child { border-bottom: none; }
337	    .proposal-list .p-icon {
338	      flex: 0 0 18px;
339	      font-size: 1rem;
340	      line-height: 1.4;
341	    }
342	    .proposal-list .p-text { color: #333; }
343	
344	    /* 選定結果タブ */
345	    #tab2-spec-table {
346	      width: 100%;
347	      border-collapse: collapse;
348	      font-size: 0.78rem;
349	    }
350	    #tab2-spec-table th {
351	      background: #eef2f9;
352	      padding: 5px 8px;
353	      text-align: left;
354	      color: #1e3a5f;
355	      border-bottom: 1px solid #c9d4e6;
356	    }
357	    #tab2-spec-table td {
358	      padding: 5px 8px;
359	      border-bottom: 1px solid #eef0f4;
360	    }
361	
362	    /* 詳細仕様タブ */
363	    .spec-block { margin-bottom: 12px; }
364	    .spec-block-title {
365	      font-size: 0.73rem;
366	      font-weight: 700;
367	      color: #3a5a8a;
368	      border-bottom: 1px solid #c9d4e6;
369	      padding-bottom: 3px;
370	      margin-bottom: 6px;
371	    }
372	    .spec-row {
373	      display: flex;
374	      gap: 6px;
375	      margin-bottom: 4px;
376	      font-size: 0.75rem;
377	    }
378	    .spec-row .sk { flex: 0 0 110px; color: #666; }
379	    .spec-row .sv { color: #1a1a1a; font-weight: 600; }
380	
381	    /* placeholder text */
382	    .placeholder-text {
383	      color: #aaa;
384	      font-size: 0.77rem;
385	      text-align: center;
386	      padding: 20px 0;
387	    }
388	  </style>
389	</head>
390	<body>
391	
392	<!-- ===================== サイドバー ===================== -->
393	<div id="sidebar">
394	  <div id="sidebar-header">
395	    <h1>ばね自動選定システム</h1>
396	    <div class="sub">プレート機構 ／ ストローク動作解析</div>
397	  </div>
398	
399	  <div class="tab-bar">
400	    <button class="tab-btn active" onclick="switchTab(0)">① 基本条件</button>
401	    <button class="tab-btn"        onclick="switchTab(1)">② 選定結果</button>
402	    <button class="tab-btn"        onclick="switchTab(2)">③ 詳細仕様</button>
403	  </div>
404	
405	  <!-- ===== タブ1：基本条件 ===== -->
406	  <div class="tab-content active" id="tab0">
407	
408	    <!-- 可動部条件 -->
409	    <div class="section">
410	      <div class="section-title">可動部条件</div>
411	
412	      <div class="form-row">
413	        <label>プレート材質</label>
414	        <select id="plate-mat" onchange="onMaterialChange()">
415	          <option value="SS400">SS400（炭素鋼）</option>
416	          <option value="SUS304">SUS304（ステンレス）</option>
417	          <option value="A5052">A5052（アルミ）</option>
418	        </select>
419	      </div>
420	      <div class="form-row">
421	        <label>プレート幅</label>
422	        <input type="number" id="plate-w" value="200" min="10" step="1">
423	        <span class="unit">mm</span>
424	      </div>
425	      <div class="form-row">
426	        <label>プレート奥行</label>
427	        <input type="number" id="plate-d" value="150" min="10" step="1">
428	        <span class="unit">mm</span>
429	      </div>
430	      <div class="form-row">
431	        <label>プレート厚さ</label>
432	        <input type="number" id="plate-t" value="10" min="1" step="1">
433	        <span class="unit">mm</span>
434	      </div>
435	      <div class="form-row">
436	        <label>搭載物重量</label>
437	        <input type="number" id="payload" value="0" min="0" step="0.1">
438	        <span class="unit">N</span>
439	      </div>
440	      <div class="form-row">
441	        <label>ストローク</label>
442	        <input type="number" id="stroke" value="30" min="1" step="1">
443	        <span class="unit">mm</span>
444	      </div>
445	    </div>
446	
447	    <!-- シャフト条件 -->
448	    <div class="section">
449	      <div class="section-title">シャフト条件</div>
450	
451	      <div class="form-row">
452	        <label>シャフト材質</label>
453	        <select id="shaft-mat" onchange="onMaterialChange()">
454	          <option value="S45C_EN">S45C＋無電解Niメッキ</option>
455	          <option value="S45C_HC">S45C＋硬質Crメッキ</option>
456	          <option value="SUS304">SUS304（無処理）</option>
457	          <option value="S45C_BARE">S45C（無処理）</option>
458	        </select>
459	      </div>
460	      <div id="shaft-mat-warn" class="material-warn"></div>
461	
462	      <div class="form-row">
463	        <label>シャフト径</label>
464	        <input type="number" id="shaft-d" value="10" min="4" step="1">
465	        <span class="unit">mm</span>
466	      </div>
467	      <div class="form-row">
468	        <label>シャフト本数</label>
469	        <select id="shaft-n">
470	          <option value="2">2本</option>
471	          <option value="4" selected>4本</option>
472	        </select>
473	      </div>
474	      <div class="form-row">
475	        <label>シャフト間隔 L</label>
476	        <input type="number" id="shaft-span" value="140" min="10" step="1">
477	        <span class="unit">mm</span>
478	      </div>
479	      <div class="hint">シャフト中心間距離（偏荷重計算に使用）</div>
480	
481	      <div class="form-row">
482	        <label>ブッシュ種別</label>
483	        <select id="bushing" onchange="onBushingChange()">
484	          <option value="ptfe">DDK05 / K5B（PTFE系）</option>
485	          <option value="pom">DBB01 / DBB（POM系）</option>
486	          <option value="bronze">HAシリーズ（青銅＋固体潤滑）</option>
487	          <option value="linear">リニアブッシュ（ボール）</option>
488	          <option value="none">ブッシュなし（直接摺動）</option>
489	        </select>
490	      </div>
491	      <div class="form-row">
492	        <label>摩擦係数 μ</label>
493	        <div class="mu-badge">μ = <span id="mu-val">0.08</span></div>
494	      </div>
495	      <div class="hint">ブッシュ種別から自動設定（大同メタル工業カタログ典型値上限）</div>
496	    </div>
497	
498	    <!-- ばね条件 -->
499	    <div class="section">
500	      <div class="section-title">ばね条件</div>
501	
502	      <div class="form-row">
503	        <label>ばね本数</label>
504	        <select id="spring-n">
505	          <option value="2">2本</option>
506	          <option value="4" selected>4本</option>
507	        </select>
508	      </div>
509	      <div class="form-row">
510	        <label>ばね間隔</label>
511	        <input type="number" id="spring-span" value="100" min="10" step="1">
512	        <span class="unit">mm</span>
513	      </div>
514	      <div class="form-row">
515	        <label>ばね自由長</label>
516	        <input type="number" id="spring-l0" value="80" min="10" step="1">
517	        <span class="unit">mm</span>
518	      </div>
519	      <div class="form-row">
520	        <label>取付長さ</label>
521	        <input type="number" id="spring-lset" value="60" min="10" step="1">
522	        <span class="unit">mm</span>
523	      </div>
524	      <div class="hint">セット位置でのたわみ = 自由長 − 取付長さ</div>
525	      <div class="form-row">
526	        <label>ばね定数 k</label>
527	        <input type="number" id="spring-k" value="5.0" min="0.1" step="0.1">
528	        <span class="unit">N/mm</span>
529	      </div>
530	    </div>
531	
532	    <!-- 荷重・偏荷重条件 -->
533	    <div class="section">
534	      <div class="section-title">荷重・偏荷重条件</div>
535	
536	      <div class="form-row">
537	        <label>荷重 P</label>
538	        <input type="number" id="load-p" value="100" min="0" step="1">
539	        <span class="unit">N</span>
540	      </div>
541	      <div class="form-row">
542	        <label>荷重位置 X</label>
543	        <input type="number" id="load-x" value="50" min="0" step="1" oninput="drawCanvas()">
544	        <span class="unit">mm</span>
545	      </div>
546	      <div class="hint" id="load-x-hint">
547	        通常、中心位置に荷重が掛かるということは少なく、プレート幅・奥行の1/4を初期値として設定しています。実際の荷重位置が分かる場合は変更してください。
548	      </div>
549	    </div>
550	
551	    <!-- 使用環境 -->
552	    <div class="section">
553	      <div class="section-title">使用環境</div>
554	
555	      <div class="form-row">
556	        <label>設置環境</label>
557	        <select id="env" onchange="onEnvChange()">
558	          <option value="indoor_dry">室内・低湿（通常環境）</option>
559	          <option value="indoor_wet">室内・高湿（結露あり）</option>
560	          <option value="outdoor">屋外・雨水あり</option>
561	          <option value="special">特殊環境（粉塵・薬品等）</option>
562	        </select>
563	      </div>
564	      <div id="env-hint" class="hint"></div>
565	    </div>
566	
567	    <button id="calc-btn" onclick="calculate()">選定・診断を実行</button>
568	  </div>
569	
570	  <!-- ===== タブ2：選定結果 ===== -->
571	  <div class="tab-content" id="tab1">
572	    <div class="section">
573	      <div class="section-title">推奨ばね仕様</div>
574	      <table id="tab2-spec-table">
575	        <thead>
576	          <tr><th>項目</th><th>推奨値</th></tr>
577	        </thead>
578	        <tbody id="tab2-spec-body">
579	          <tr><td colspan="2" class="placeholder-text">計算を実行してください</td></tr>
580	        </tbody>
581	      </table>
582	    </div>
583	    <div class="section">
584	      <div class="section-title">推奨材料・表面処理</div>
585	      <div id="tab2-material" class="placeholder-text">計算を実行してください</div>
586	    </div>
587	  </div>
588	
589	  <!-- ===== タブ3：詳細仕様 ===== -->
590	  <div class="tab-content" id="tab2">
591	    <div id="tab3-body">
592	      <div class="placeholder-text">計算を実行してください</div>
593	    </div>
594	  </div>
595	
596	</div><!-- /sidebar -->
597	
598	
599	<!-- ===================== メインエリア ===================== -->
600	<div id="main">
601	  <div id="main-header">
