778	function drawTopView(ctx, W, panelY, panelH, plateWmm, plateDmm, shaftSpan, springSpan, loadXmm) {
779	  ctx.font = 'bold 10px sans-serif'; ctx.fillStyle = '#1e3a5f'; ctx.textAlign = 'left';
780	  ctx.fillText('A) ばね配置図（上面図）', 8, panelY + 12);
781	
782	  const availW = W * 0.55, availH = panelH - 28;
783	  const sc  = Math.min(availW / plateWmm, availH / plateDmm) * 0.85;
784	  const pW  = plateWmm * sc, pH = plateDmm * sc;
785	  const cx  = W / 2 - 10, cy = panelY + 20 + availH / 2;
786	  const pL  = cx - pW / 2, pT = cy - pH / 2;
787	
788	  // プレート
789	  ctx.fillStyle = '#eceff1'; ctx.fillRect(pL, pT, pW, pH);
790	  ctx.strokeStyle = '#546e7a'; ctx.lineWidth = 1.5; ctx.strokeRect(pL, pT, pW, pH);
791	
792	  // 中心十字線（点線）
793	  ctx.strokeStyle = '#bbb'; ctx.lineWidth = 0.7; ctx.setLineDash([3, 3]);
794	  ctx.beginPath(); ctx.moveTo(cx - pW/2 - 10, cy); ctx.lineTo(cx + pW/2 + 10, cy); ctx.stroke();
795	  ctx.beginPath(); ctx.moveTo(cx, cy - pH/2 - 10); ctx.lineTo(cx, cy + pH/2 + 10); ctx.stroke();
796	  ctx.setLineDash([]);
797	
798	  // X / Y 軸ラベル
799	  ctx.fillStyle = '#888'; ctx.font = '10px sans-serif';
800	  ctx.textAlign = 'center'; ctx.fillText('Y', cx, pT - 12);
801	  ctx.textAlign = 'left';   ctx.fillText('X', pL + pW + 12, cy + 4);
802	
803	  // 位置計算
804	  const shX = (shaftSpan * sc) / 2;
805	  const shY = shX * (plateDmm / plateWmm);
806	  const spX = (springSpan * sc) / 2;
807	  const spY = spX * (plateDmm / plateWmm);
808	
809	  // シャフト穴（薄いグレー丸）
810	  [[cx-shX,cy-shY],[cx+shX,cy-shY],[cx-shX,cy+shY],[cx+shX,cy+shY]].forEach(([x,y]) => {
811	    ctx.fillStyle = '#cfd8dc'; ctx.beginPath(); ctx.arc(x, y, 6, 0, Math.PI*2); ctx.fill();
812	    ctx.strokeStyle = '#78909c'; ctx.lineWidth = 1; ctx.stroke();
813	    ctx.strokeStyle = '#546e7a'; ctx.lineWidth = 0.8;
814	    ctx.beginPath(); ctx.moveTo(x-3,y); ctx.lineTo(x+3,y); ctx.stroke();
815	    ctx.beginPath(); ctx.moveTo(x,y-3); ctx.lineTo(x,y+3); ctx.stroke();
816	  });
817	
818	  // ばね（青い丸＋十字＋ラベル）
819	  [
820	    [cx-spX, cy-spY, 'ばね1', true],
821	    [cx+spX, cy-spY, 'ばね2', true],
822	    [cx-spX, cy+spY, 'ばね3', false],
823	    [cx+spX, cy+spY, 'ばね4', false]
824	  ].forEach(([x, y, lbl, above]) => {
825	    ctx.fillStyle = '#1e88e5'; ctx.beginPath(); ctx.arc(x, y, 11, 0, Math.PI*2); ctx.fill();
826	    ctx.strokeStyle = '#0d47a1'; ctx.lineWidth = 1; ctx.stroke();
827	    ctx.fillStyle = '#fff'; ctx.beginPath(); ctx.arc(x, y, 5, 0, Math.PI*2); ctx.fill();
828	    ctx.strokeStyle = '#fff'; ctx.lineWidth = 1.8;
829	    ctx.beginPath(); ctx.moveTo(x-3.5,y); ctx.lineTo(x+3.5,y); ctx.stroke();
830	    ctx.beginPath(); ctx.moveTo(x,y-3.5); ctx.lineTo(x,y+3.5); ctx.stroke();
831	    ctx.fillStyle = '#0d47a1'; ctx.font = '8px sans-serif'; ctx.textAlign = 'center';
832	    ctx.fillText(lbl, x, above ? y - 14 : y + 22);
833	  });
834	
835	  // 荷重点（オレンジ）
836	  const lx = cx + loadXmm * sc;
837	  ctx.fillStyle = '#fb8c00'; ctx.beginPath(); ctx.arc(lx, cy, 7, 0, Math.PI*2); ctx.fill();
838	  ctx.strokeStyle = '#e65100'; ctx.lineWidth = 1; ctx.stroke();
839	  ctx.fillStyle = '#e65100'; ctx.font = '8px sans-serif'; ctx.textAlign = 'left';
840	  ctx.fillText('荷重点', lx + 9, cy + 3);
841	
842	  // シャフト間隔 寸法線
843	  const dimY = pT + pH + 14;
844	  ctx.strokeStyle = '#888'; ctx.lineWidth = 0.8;
845	  [[cx-shX, cx+shX]].forEach(([x1, x2]) => {
846	    ctx.beginPath(); ctx.moveTo(x1, dimY-4); ctx.lineTo(x1, dimY+4); ctx.stroke();
847	    ctx.beginPath(); ctx.moveTo(x2, dimY-4); ctx.lineTo(x2, dimY+4); ctx.stroke();
848	    ctx.beginPath(); ctx.moveTo(x1, dimY);   ctx.lineTo(x2, dimY);   ctx.stroke();
849	  });
850	  ctx.fillStyle = '#555'; ctx.font = '9px sans-serif'; ctx.textAlign = 'center';
851	  ctx.fillText(`L = ${shaftSpan}mm`, cx, dimY + 11);
852	
853	  // 凡例（プレート右）
854	  let ly = pT + 10; const lx2 = pL + pW + 12;
855	  [[{c:'#1e88e5',r:6},'ばね'],[{c:'#cfd8dc',r:5},'シャフト'],[{c:'#fb8c00',r:5},'荷重点']].forEach(([{c,r}, label]) => {
856	    ctx.fillStyle = c; ctx.beginPath(); ctx.arc(lx2+6, ly, r, 0, Math.PI*2); ctx.fill();
857	    if (c === '#cfd8dc') { ctx.strokeStyle = '#78909c'; ctx.lineWidth = 0.8; ctx.stroke(); }
858	    ctx.fillStyle = '#333'; ctx.font = '8.5px sans-serif'; ctx.textAlign = 'left';
859	    ctx.fillText(label, lx2+14, ly+3);
860	    ly += 15;
861	  });
862	}
