864	function drawSideView(ctx, W, panelY, panelH, plateWmm, shaftSpan, springSpan, strokeMm, loadXmm) {
865	  // 区切り線
866	  ctx.strokeStyle = '#dde1e7'; ctx.lineWidth = 1;
867	  ctx.beginPath(); ctx.moveTo(8, panelY-2); ctx.lineTo(W-8, panelY-2); ctx.stroke();
868	
869	  ctx.font = 'bold 10px sans-serif'; ctx.fillStyle = '#1e3a5f'; ctx.textAlign = 'left';
870	  ctx.fillText('B) 動作イメージ（側面・概念図）', 8, panelY + 12);
871	
872	  const lm = 52, rm = 128, cw = W - lm - rm;
873	  const cx = lm + cw / 2;
874	  const sc = Math.min((cw * 0.65) / shaftSpan, 1.6);
875	  const shHalf = (shaftSpan * sc) / 2;
876	  const spHalf = Math.min((springSpan * sc) / 2, shHalf - 18);
877	  const spR    = Math.max(9, Math.min(13, spHalf * 0.24));
878	  const shR    = 8;
879	
880	  // Y座標
881	  const ct = panelY + 24, cb = panelY + panelH - 10;
882	  const baseH = 10, plateThk = 20;
883	  const baseTop  = cb - baseH;
884	  const sprBotY  = baseTop;
885	  const sprH     = (cb - ct) * 0.46;
886	  const sprTopY  = sprBotY - sprH;
887	  const movTop   = sprTopY - plateThk;
888	  const strokePx = Math.min(strokeMm * sc, sprH * 0.38);
889	
890	  // --- ベースプレート ---
891	  const bw = shHalf * 2 + 36;
892	  ctx.fillStyle = '#546e7a'; ctx.fillRect(cx - bw/2, baseTop, bw, baseH);
893	  ctx.fillStyle = '#78909c'; ctx.fillRect(cx - bw/2, baseTop, bw, 2);
894	  ctx.strokeStyle = '#263238'; ctx.lineWidth = 1; ctx.strokeRect(cx - bw/2, baseTop, bw, baseH);
895	  ctx.fillStyle = '#555'; ctx.font = '8.5px sans-serif'; ctx.textAlign = 'center';
896	  ctx.fillText('ベースプレート（固定）', cx, cb - 1);
897	
898	  // --- ばね（前面2本）---
899	  drawCoilSpring(ctx, cx - spHalf, sprTopY, sprBotY, spR);
900	  drawCoilSpring(ctx, cx + spHalf, sprTopY, sprBotY, spR);
901	
902	  // --- シャフト奥ペア（半透明）---
903	  ctx.globalAlpha = 0.42;
904	  drawShaftCylinder(ctx, cx - shHalf + 5, movTop, baseTop, shR - 2);
905	  drawShaftCylinder(ctx, cx + shHalf + 5, movTop, baseTop, shR - 2);
906	  ctx.globalAlpha = 1;
907	
908	  // --- シャフト手前ペア ---
909	  drawShaftCylinder(ctx, cx - shHalf, movTop, baseTop, shR);
910	  drawShaftCylinder(ctx, cx + shHalf, movTop, baseTop, shR);
911	
912	  // --- ストローク点線 ---
913	  ctx.strokeStyle = '#42a5f5'; ctx.lineWidth = 1; ctx.setLineDash([5, 4]);
914	  [cx - shHalf, cx + shHalf].forEach(sx => {
915	    ctx.beginPath(); ctx.moveTo(sx-shR-6, movTop+plateThk); ctx.lineTo(sx+shR+6, movTop+plateThk); ctx.stroke();
916	    ctx.beginPath(); ctx.moveTo(sx-shR-6, movTop+plateThk+strokePx); ctx.lineTo(sx+shR+6, movTop+plateThk+strokePx); ctx.stroke();
917	  });
918	  ctx.setLineDash([]);
919	
920	  // --- 可動プレート ---
921	  const mpW = shHalf * 2 + 28;
922	  ctx.fillStyle = '#78909c'; ctx.fillRect(cx - mpW/2, movTop, mpW, plateThk);
923	  ctx.fillStyle = '#cfd8dc'; ctx.fillRect(cx - mpW/2, movTop, mpW, 3);
924	  ctx.strokeStyle = '#37474f'; ctx.lineWidth = 1; ctx.strokeRect(cx - mpW/2, movTop, mpW, plateThk);
925	  ctx.fillStyle = '#fff'; ctx.font = 'bold 9px sans-serif'; ctx.textAlign = 'center';
926	  ctx.fillText('可動プレート', cx, movTop + 13);
927	
928	  // --- 偏荷重矢印（オレンジ）---
929	  const lxpx = Math.min(loadXmm * sc, shHalf - 4);
930	  const ax = cx + lxpx, at = movTop - 40;
931	  ctx.strokeStyle = '#e65100'; ctx.lineWidth = 3;
932	  ctx.beginPath(); ctx.moveTo(ax, at); ctx.lineTo(ax, movTop); ctx.stroke();
933	  ctx.fillStyle = '#e65100';
934	  ctx.beginPath(); ctx.moveTo(ax, movTop); ctx.lineTo(ax-7, movTop-12); ctx.lineTo(ax+7, movTop-12); ctx.closePath(); ctx.fill();
935	  // 吹き出し
936	  roundRect(ctx, ax+6, at-2, 48, 16, 3);
937	  ctx.fillStyle = '#fff8e1'; ctx.fill();
938	  ctx.strokeStyle = '#f57f17'; ctx.lineWidth = 0.8; ctx.stroke();
939	  ctx.fillStyle = '#bf360c'; ctx.font = 'bold 8.5px sans-serif'; ctx.textAlign = 'left';
940	  ctx.fillText('偏荷重', ax+10, at+11);
941	
942	  // --- 右側ラベル ---
943	  const rx = cx + shHalf + shR + 10;
944	  drawCallout(ctx, rx, movTop + plateThk/2 + 6, ['右側2本に', '荷重集中'],        '#fff3e0', '#e65100');
945	  drawCallout(ctx, rx, movTop + plateThk + sprH*0.5, ['4点支持で', '姿勢は安定', 'しやすい'], '#e8f5e9', '#2e7d32');
946	
947	  // --- 左ガイドシャフトラベル ---
948	  ctx.fillStyle = '#546e7a'; ctx.font = '9px sans-serif'; ctx.textAlign = 'right';
949	  const smY = (movTop + baseTop) / 2;
950	  ctx.fillText('ガイド',    cx - shHalf - shR - 5, smY - 2);
951	  ctx.fillText('シャフト',  cx - shHalf - shR - 5, smY + 10);
952	  ctx.strokeStyle = '#90a4ae'; ctx.lineWidth = 0.8;
953	  ctx.beginPath(); ctx.moveTo(cx-shHalf-shR-3, smY+3); ctx.lineTo(cx-shHalf-shR, smY+3); ctx.stroke();
954	}
955	
956	function drawCallout(ctx, x, y, lines, bg, border) {
957	  const lh = 12, pad = 5, bw = 74, bh = lines.length * lh + pad * 2 - 2;
958	  const by = y - bh / 2;
959	  roundRect(ctx, x, by, bw, bh, 3);
960	  ctx.fillStyle = bg; ctx.fill();
961	  ctx.strokeStyle = border; ctx.lineWidth = 0.8; ctx.stroke();
962	  ctx.beginPath(); ctx.moveTo(x, y); ctx.lineTo(x-7, y); ctx.stroke();
963	  ctx.fillStyle = border; ctx.font = '8.5px sans-serif'; ctx.textAlign = 'left';
964	  lines.forEach((ln, i) => ctx.fillText(ln, x + pad, by + pad + 10 + i * lh));
965	}
966	
967	function roundRect(ctx, x, y, w, h, r) {
968	  ctx.beginPath();
969	  ctx.moveTo(x+r, y); ctx.lineTo(x+w-r, y); ctx.quadraticCurveTo(x+w, y, x+w, y+r);
970	  ctx.lineTo(x+w, y+h-r); ctx.quadraticCurveTo(x+w, y+h, x+w-r, y+h);
971	  ctx.lineTo(x+r, y+h); ctx.quadraticCurveTo(x, y+h, x, y+h-r);
972	  ctx.lineTo(x, y+r); ctx.quadraticCurveTo(x, y, x+r, y);
973	  ctx.closePath();
974	}
975	
976	function drawCoilSpring(ctx, cx, topY, botY, outerR) {
977	  const numCoils = 7;
978	  const totalH = botY - topY;
979	  const endH = Math.min(10, totalH * 0.08);
980	  const coilTop = topY + endH;
981	  const coilBot = botY - endH;
982	
983	  // 上下の直線端部
984	  ctx.strokeStyle = '#455a64'; ctx.lineWidth = 2;
985	  ctx.beginPath(); ctx.moveTo(cx, topY); ctx.lineTo(cx, coilTop); ctx.stroke();
986	  ctx.beginPath(); ctx.moveTo(cx, coilBot); ctx.lineTo(cx, botY); ctx.stroke();
987	
988	  // サイン波で全点を生成（front=手前側, back=奥側）
989	  const totalSteps = numCoils * 40;
990	  const pts = [];
991	  for (let i = 0; i <= totalSteps; i++) {
992	    const t = i / totalSteps;
993	    const angle = t * numCoils * Math.PI * 2;
994	    pts.push({
995	      x: cx + outerR * Math.sin(angle),
996	      y: coilTop + t * (coilBot - coilTop),
997	      front: Math.sin(angle) >= 0
998	    });
999	  }
1000	
1001	  // 奥側（薄・細）を先に描画
1002	  ctx.strokeStyle = '#90a4ae'; ctx.lineWidth = 1.5;
1003	  let seg = false;
1004	  for (let i = 0; i < pts.length; i++) {
1005	    if (!pts[i].front) {
1006	      if (!seg) { ctx.beginPath(); ctx.moveTo(pts[i].x, pts[i].y); seg = true; }
1007	      else ctx.lineTo(pts[i].x, pts[i].y);
1008	    } else { if (seg) { ctx.stroke(); seg = false; } }
1009	  }
1010	  if (seg) ctx.stroke();
1011	
1012	  // 手前側（濃・太）を上書き
1013	  ctx.strokeStyle = '#37474f'; ctx.lineWidth = 2.5;
1014	  seg = false;
1015	  for (let i = 0; i < pts.length; i++) {
1016	    if (pts[i].front) {
1017	      if (!seg) { ctx.beginPath(); ctx.moveTo(pts[i].x, pts[i].y); seg = true; }
1018	      else ctx.lineTo(pts[i].x, pts[i].y);
1019	    } else { if (seg) { ctx.stroke(); seg = false; } }
1020	  }
1021	  if (seg) ctx.stroke();
1022	}
1023	
1024	function drawShaftCylinder(ctx, cx, topY, botY, r) {
1025	  // 円柱本体（左→右グラデーション）
1026	  const grad = ctx.createLinearGradient(cx - r, 0, cx + r, 0);
1027	  grad.addColorStop(0,    '#263238');
1028	  grad.addColorStop(0.22, '#cfd8dc');
1029	  grad.addColorStop(0.55, '#78909c');
1030	  grad.addColorStop(1,    '#37474f');
1031	  ctx.fillStyle = grad;
1032	  ctx.fillRect(cx - r, topY, r * 2, botY - topY);
1033	  ctx.strokeStyle = '#263238'; ctx.lineWidth = 0.8;
1034	  ctx.strokeRect(cx - r, topY, r * 2, botY - topY);
1035	
1036	  // 上面楕円（明るい）
1037	  ctx.fillStyle = '#eceff1';
1038	  ctx.beginPath();
1039	  ctx.ellipse(cx, topY, r, r * 0.35, 0, 0, Math.PI * 2);
1040	  ctx.fill();
1041	  ctx.strokeStyle = '#546e7a'; ctx.lineWidth = 0.7;
1042	  ctx.stroke();
1043	
1044	  // 下面楕円（暗い）
1045	  ctx.fillStyle = '#546e7a';
1046	  ctx.beginPath();
1047	  ctx.ellipse(cx, botY, r, r * 0.35, 0, 0, Math.PI * 2);
1048	  ctx.fill();
1049	  ctx.stroke();
1050	}
1051	
1052	function drawArrowHead(ctx, x, y, color, dir) {
1053	  const s = 6;
1054	  ctx.fillStyle = color;
1055	  ctx.beginPath();
1056	  if (dir === 'down') {
1057	    ctx.moveTo(x, y); ctx.lineTo(x - s/2, y - s); ctx.lineTo(x + s/2, y - s);
1058	  } else if (dir === 'up') {
1059	    ctx.moveTo(x, y); ctx.lineTo(x - s/2, y + s); ctx.lineTo(x + s/2, y + s);
1060	  } else if (dir === 'right') {
1061	    ctx.moveTo(x, y); ctx.lineTo(x - s, y - s/2); ctx.lineTo(x - s, y + s/2);
1062	  }
1063	  ctx.closePath(); ctx.fill();
1064	}
1065	
1066	/* =====================================================
1067	   計算（ダミー実装 → 実計算はここに追加）
1068	===================================================== */
1069	function calculate() {
1070	  const plateMat   = document.getElementById('plate-mat').value;
1071	  const plateW_mm  = parseFloat(document.getElementById('plate-w').value);
1072	  const plateD_mm  = parseFloat(document.getElementById('plate-d').value);
1073	  const plateT_mm  = parseFloat(document.getElementById('plate-t').value);
1074	  const payload    = parseFloat(document.getElementById('payload').value);
1075	  const stroke     = parseFloat(document.getElementById('stroke').value);
1076	  const shaftSpan  = parseFloat(document.getElementById('shaft-span').value);
1077	  const shaftN     = parseInt(document.getElementById('shaft-n').value);
1078	  const bushing    = document.getElementById('bushing').value;
1079	  const springN    = parseInt(document.getElementById('spring-n').value);
1080	  const springL0   = parseFloat(document.getElementById('spring-l0').value);
1081	  const springLset = parseFloat(document.getElementById('spring-lset').value);
1082	  const springK    = parseFloat(document.getElementById('spring-k').value);
1083	  const loadP      = parseFloat(document.getElementById('load-p').value);
1084	  const loadX      = parseFloat(document.getElementById('load-x').value);
1085	
1086	  const mu = MU_TABLE[bushing] ?? 0.20;
1087	
1088	  // 可動部重量
1089	  const rho = DENSITY[plateMat] ?? 7.85e-3; // g/mm³
1090	  const plateVol = plateW_mm * plateD_mm * plateT_mm; // mm³
1091	  const plateWeight = plateVol * rho * 9.81 / 1000; // N (g→kg→N)
1092	  const W_total = plateWeight + payload;
1093	
1094	  // ばね力（セット位置）
1095	  const delta_set = springL0 - springLset;
1096	  const F_spring = springK * delta_set * springN;
1097	
1098	  // シャフト反力（偏荷重）
1099	  const F_N = (loadP * loadX) / shaftSpan;
1100	
1101	  // 摩擦力
1102	  const F_friction = mu * F_N * shaftN;
1103	
1104	  // 自己ロック判定
1105	  const lockRatio = mu * loadX / (shaftSpan / 2);
1106	  const isLocked = lockRatio >= 1;
1107	
1108	  // 戻り判定
1109	  const canReturn = F_spring >= W_total + F_friction;
1110	  const isHeavy   = !canReturn ? false : F_spring < W_total + F_friction * 1.5;
1111	
1112	  // 偏荷重判定（F_N / loadP ratio）
1113	  const eccentricRatio = F_N / (loadP || 1);
1114	
1115	  // 摺動材料判定
1116	  const shaftMat = document.getElementById('shaft-mat').value;
1117	  const matNg = shaftMat === 'S45C_BARE' ||
1118	    (shaftMat === 'SUS304' && bushing === 'none');
1119	
1120	  // ---------- 診断グリッド更新 ----------
1121	  const diagData = [
1122	    {
1123	      label: '自己ロック',
1124	      cls: isLocked ? 'ng-item' : 'ok-item',
1125	      val: isLocked ? `NG（比率 ${lockRatio.toFixed(2)}）` : `OK（比率 ${lockRatio.toFixed(2)}）`
1126	    },
1127	    {
1128	      label: '戻り動作',
1129	      cls: isLocked ? 'pending-item' : canReturn ? (isHeavy ? 'warn-item' : 'ok-item') : 'ng-item',
1130	      val: isLocked ? '—（ロック）' : canReturn ? (isHeavy ? '要注意' : 'OK') : 'NG'
1131	    },
1132	    {
1133	      label: '偏荷重',
1134	      cls: eccentricRatio > 0.5 ? 'warn-item' : 'ok-item',
1135	      val: `F_N = ${F_N.toFixed(1)} N`
1136	    },
1137	    {
1138	      label: '姿勢安定',
1139	      cls: shaftN >= 4 ? 'ok-item' : 'warn-item',
1140	      val: shaftN >= 4 ? 'OK（4本）' : '要注意（2本）'
1141	    },
1142	    {
1143	      label: '振動・共振',
1144	      cls: 'pending-item',
1145	      val: '別途確認'
1146	    },
1147	    {
1148	      label: '摺動材料',
1149	      cls: matNg ? 'ng-item' : 'ok-item',
1150	      val: matNg ? 'NG' : 'OK'
1151	    }
1152	  ];
1153	
1154	  const grid = document.getElementById('diag-grid');
1155	  grid.innerHTML = diagData.map(d => `
1156	    <div class="diag-item ${d.cls}">
1157	      <div class="diag-label">${d.label}</div>
1158	      <div class="diag-val">${d.val}</div>
1159	    </div>`).join('');
1160	
1161	  // ---------- 総合ステータスバッジ ----------
1162	  const badge = document.getElementById('overall-badge');
1163	  if (isLocked || !canReturn || matNg) {
1164	    badge.className = 'status-badge ng'; badge.textContent = '要修正';
1165	  } else if (isHeavy || eccentricRatio > 0.5 || shaftN < 4) {
1166	    badge.className = 'status-badge warn'; badge.textContent = '要注意';
1167	  } else {
1168	    badge.className = 'status-badge ok'; badge.textContent = 'OK';
1169	  }
1170	
1171	  // ---------- 選定ばね仕様（メイン） ----------
1172	  document.getElementById('result-spec-area').innerHTML = `
1173	    <table class="result-table">
1174	      <thead><tr><th>項目</th><th>値</th></tr></thead>
1175	      <tbody>
1176	        <tr><td>ばね本数</td><td class="highlight">${springN} 本</td></tr>
1177	        <tr><td>ばね定数 k</td><td class="highlight">${springK} N/mm</td></tr>
1178	        <tr><td>自由長</td><td>${springL0} mm</td></tr>
1179	        <tr><td>取付長さ（セット）</td><td>${springLset} mm</td></tr>
1180	        <tr><td>セットたわみ δ</td><td>${delta_set.toFixed(1)} mm</td></tr>
1181	        <tr><td>ばね合計セット力</td><td class="highlight">${F_spring.toFixed(1)} N</td></tr>
1182	        <tr><td>可動部重量 W</td><td>${W_total.toFixed(1)} N</td></tr>
1183	        <tr><td>摩擦力 F_f</td><td>${F_friction.toFixed(1)} N</td></tr>
1184	        <tr><td>余裕率（ばね力 / (W+F_f)）</td><td class="highlight">${((F_spring/(W_total+F_friction+0.001))).toFixed(2)}</td></tr>
1185	      </tbody>
1186	    </table>`;
1187	
1188	  // ---------- タブ2：推奨ばね仕様 ----------
1189	  document.getElementById('tab2-spec-body').innerHTML = `
1190	    <tr><td>推奨ばね本数</td><td>${springN}本</td></tr>
1191	    <tr><td>推奨ばね定数</td><td>${springK} N/mm</td></tr>
1192	    <tr><td>推奨自由長</td><td>${springL0} mm</td></tr>
1193	    <tr><td>ストローク</td><td>${stroke} mm</td></tr>
1194	    <tr><td>合計セット力</td><td>${F_spring.toFixed(1)} N</td></tr>`;
1195	
1196	  const matHtml = `
1197	    <div class="spec-block">
1198	      <div class="spec-row"><span class="sk">シャフト材質</span><span class="sv">${SHAFT_MAT_LABEL[shaftMat]}</span></div>
1199	      <div class="spec-row"><span class="sk">ブッシュ</span><span class="sv">${document.getElementById('bushing').selectedOptions[0].text}</span></div>
1200	      <div class="spec-row"><span class="sk">摩擦係数 μ</span><span class="sv">${mu}</span></div>
1201	    </div>`;
1202	  document.getElementById('tab2-material').innerHTML = matHtml;
1203	
1204	  // ---------- タブ3：詳細仕様 ----------
1205	  document.getElementById('tab3-body').innerHTML = `
1206	    <div class="spec-block">
1207	      <div class="spec-block-title">計算根拠</div>
1208	      <div class="spec-row"><span class="sk">シャフト反力 F_N</span><span class="sv">${F_N.toFixed(2)} N</span></div>
1209	      <div class="spec-row"><span class="sk">摩擦力 F_friction</span><span class="sv">${F_friction.toFixed(2)} N</span></div>
1210	      <div class="spec-row"><span class="sk">自己ロック比率</span><span class="sv">μ×X÷(L/2) = ${lockRatio.toFixed(3)}</span></div>
1211	      <div class="spec-row"><span class="sk">ばね合計セット力</span><span class="sv">${F_spring.toFixed(2)} N</span></div>
1212	      <div class="spec-row"><span class="sk">必要ばね力（1.5倍）</span><span class="sv">${(W_total + F_friction * 1.5).toFixed(2)} N</span></div>
1213	    </div>
1214	    <div class="spec-block">
1215	      <div class="spec-block-title">使用μ値の根拠</div>
1216	      <div class="spec-row"><span class="sk">情報源</span><span class="sv">大同メタル工業カタログ</span></div>
1217	      <div class="spec-row"><span class="sk">採用方針</span><span class="sv">動摩擦係数の典型値上限</span></div>
1218	      <div class="spec-row"><span class="sk">採用μ</span><span class="sv">${mu}（${document.getElementById('bushing').selectedOptions[0].text}）</span></div>
1219	    </div>
1220	    <div class="spec-block">
1221	      <div class="spec-block-title">判定閾値</div>
1222	      <div class="spec-row"><span class="sk">自己ロック</span><span class="sv">μ×X÷(L/2) ≥ 1</span></div>
1223	      <div class="spec-row"><span class="sk">戻り不可</span><span class="sv">F_spring &lt; W + F_friction</span></div>
1224	      <div class="spec-row"><span class="sk">戻りが重い</span><span class="sv">F_spring &lt; W + F_friction × 1.5</span></div>
1225	    </div>`;
1226	
1227	  // ---------- 改善提案 ----------
1228	  const proposals = [];
1229	  if (isLocked) {
1230	    proposals.push({ icon: '🔴', text: '自己ロックが発生しています。荷重位置 X を短くするか、シャフト間隔 L を広げてください。' });
1231	  }
1232	  if (!canReturn && !isLocked) {
1233	    proposals.push({ icon: '🔴', text: `ばね力が不足しています。ばね定数を大きくするか本数を増やしてください。必要: ${(W_total + F_friction).toFixed(1)} N、現在: ${F_spring.toFixed(1)} N。` });
1234	  }
1235	  if (isHeavy) {
1236	    proposals.push({ icon: '🟡', text: `戻り力のマージンが不足しています（1.5倍未満）。ばね力を ${(W_total + F_friction * 1.5).toFixed(1)} N 以上にしてください。` });
1237	  }
1238	  if (matNg) {
1239	    proposals.push({ icon: '🔴', text: '摺動材料の組み合わせに問題があります。表面処理またはブッシュを見直してください。' });
1240	  }
1241	  if (bushing === 'pom' || bushing === 'bronze') {
1242	    proposals.push({ icon: '💡', text: `摩擦係数を下げるには DDK05/K5B（PTFE系、μ=0.08）への変更を検討してください。現在 μ=${mu}。` });
1243	  }
1244	  if (eccentricRatio > 0.5) {
1245	    proposals.push({ icon: '🟡', text: `偏荷重比率が高めです（F_N/P = ${eccentricRatio.toFixed(2)}）。荷重位置を中心寄りにするか、シャフト間隔を広げてください。` });
1246	  }
1247	  if (shaftN < 4) {
1248	    proposals.push({ icon: '🟡', text: '2本シャフト構成は姿勢安定性が低くなります。4本構成への変更を検討してください。' });
1249	  }
1250	  if (proposals.length === 0) {
1251	    proposals.push({ icon: '✅', text: 'すべての診断項目をクリアしています。' });
1252	  }
1253	
1254	  document.getElementById('proposal-list').innerHTML = proposals
1255	    .map(p => `<li><span class="p-icon">${p.icon}</span><span class="p-text">${p.text}</span></li>`)
1256	    .join('');
1257	
1258	  drawCanvas();
1259	  switchTab(0);
1260	}
1261	
1262	/* =====================================================
1263	   荷重位置デフォルト（プレート幅の1/4）
1264	===================================================== */
1265	function setLoadXDefault() {
1266	  const pw = parseFloat(document.getElementById('plate-w').value) || 200;
1267	  document.getElementById('load-x').value = (pw / 4).toFixed(0);
1268	  drawCanvas();
1269	}
1270	document.getElementById('plate-w').addEventListener('change', setLoadXDefault);
1271	
1272	/* =====================================================
1273	   初期化
1274	===================================================== */
1275	window.addEventListener('load', () => {
1276	  onBushingChange();
1277	  onEnvChange();
1278	  onMaterialChange();
1279	  setLoadXDefault();
1280	  drawCanvas();
1281	});
1282	
1283	window.addEventListener('resize', () => {
1284	  const wrap = document.getElementById('canvas-wrap');
1285	  const canvas = document.getElementById('install-canvas');
1286	  const maxW = wrap.clientWidth - 20;
1287	  const maxH = wrap.clientHeight - 20;
1288	  const scale = Math.min(maxW / 480, maxH / 460, 1);
1289	  canvas.style.width  = (480 * scale) + 'px';
1290	  canvas.style.height = (460 * scale) + 'px';
1291	});
1292	</script>
1293	</body>
1294	</html>
